import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { MapContainer, TileLayer, Marker, Popup } from 'react-leaflet';
import { Store, Plus, MapPin as MapIcon, Loader2 } from 'lucide-react';
import { useAuth } from '../context/AuthContext';
import { api } from '../services/api';
import ModalNuevaSucursal from './ModalNuevaSucursal';
import 'leaflet/dist/leaflet.css';
import L from 'leaflet';

// Corregir iconos de Leaflet (bug común en React)
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon-2x.png',
  iconUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon.png',
  shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-shadow.png',
});

const Dashboard = () => {
  const navigate = useNavigate();
  const { user } = useAuth(); // Obtenemos el usuario real de la base de datos
  const [showModal, setShowModal] = useState(false);
  const [locales, setLocales] = useState([]);
  const [loading, setLoading] = useState(true);

  // Cargar locales reales desde la API
  useEffect(() => {
    if (user?.id) {
      cargarLocales();
    }
  }, [user?.id]);

  const cargarLocales = async () => {
    setLoading(true);
    try {
      const data = await api.getLocalesVendedor(user.id);
      setLocales(data);
    } catch (error) {
      console.error("Error al cargar locales de la API:", error);
    } finally {
      setLoading(false);
    }
  };

  const agregarSucursal = async (datosCompletos) => {
    try {
      // Enviamos a la API con el ID del vendedor logueado
      await api.crearLocal({ ...datosCompletos, vendedorId: user.id });
      setShowModal(false);
      cargarLocales(); // Recargamos la lista actualizada
    } catch (error) {
      alert("Error al guardar la sucursal en el servidor.");
    }
  };

  if (loading) return (
    <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh', color: '#e67e22' }}>
      <Loader2 size={40} className="spinner" />
      <style>{`.spinner { animation: spin 1s linear infinite; } @keyframes spin { to { transform: rotate(360deg); } }`}</style>
    </div>
  );

  return (
    <div style={{ display: 'flex', height: 'calc(100vh - 75px)', background: '#f8fafc' }}>
      {/* SIDEBAR IZQUIERDO */}
      <div style={sidebarStyle}>
        <div style={{ marginBottom: '30px' }}>
          <h2 style={{ margin: 0, color: '#1e293b', display: 'flex', alignItems: 'center', gap: '12px' }}>
            <Store size={28} color="#e67e22" /> Mis Locales
          </h2>
          <p style={{ color: '#64748b', fontSize: '0.9rem' }}>Gestiona tus puntos de venta reales</p>
        </div>
        
        <div style={{ flex: 1, overflowY: 'auto', paddingRight: '5px' }}>
          {locales.length > 0 ? locales.map(local => (
            <div key={local._id} style={cardStyle}>
              <div style={{ flex: 1 }}>
                <strong style={{ display: 'block', color: '#1e293b' }}>{local.nombre}</strong>
                <div style={{ display: 'flex', alignItems: 'center', gap: '5px', marginTop: '4px' }}>
                   <MapIcon size={12} color="#94a3b8" />
                   <span style={{ fontSize: '0.75rem', color: '#64748b' }}>{local.ciudad || 'Ubicación registrada'}</span>
                </div>
              </div>
              <button onClick={() => navigate(`/ofertas/${local._id}`)} style={btnOfertaStyle}>
                Gestionar
              </button>
            </div>
          )) : (
            <div style={{ textAlign: 'center', padding: '40px 20px', color: '#94a3b8' }}>
              <p>No tienes sucursales en la base de datos.</p>
            </div>
          )}
        </div>

        <button onClick={() => setShowModal(true)} style={btnNuevaSucursal}>
          <Plus size={20} /> Registrar Sucursal
        </button>
      </div>

      {/* MAPA DERECHO */}
      <div style={{ flex: 1, position: 'relative' }}>
        <MapContainer 
          center={locales.length > 0 ? locales[0].coords : [-26.816, -65.230]} 
          zoom={13} 
          style={{ height: '100%', width: '100%' }}
        >
          <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
          {locales.map(local => (
            <Marker key={local._id} position={local.coords}>
              <Popup>
                <div style={{ padding: '5px' }}>
                  <strong style={{ color: '#e67e22' }}>{local.nombre}</strong><br/>
                  <span style={{ fontSize: '0.8rem' }}>{local.direccion}</span>
                </div>
              </Popup>
            </Marker>
          ))}
        </MapContainer>
      </div>

      {showModal && (
        <ModalNuevaSucursal 
          onClose={() => setShowModal(false)} 
          onSave={agregarSucursal} 
        />
      )}
    </div>
  );
};

// Estilos de la estética original que pediste
const sidebarStyle = { width: '400px', padding: '30px', background: 'white', borderRight: '1px solid #e2e8f0', display: 'flex', flexDirection: 'column', boxShadow: '10px 0 15px rgba(0,0,0,0.02)' };
const cardStyle = { padding: '20px', background: '#ffffff', borderRadius: '16px', marginBottom: '15px', display: 'flex', alignItems: 'center', border: '1px solid #f1f5f9', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)' };
const btnOfertaStyle = { background: 'rgba(230, 126, 34, 0.1)', color: '#e67e22', border: '1px solid #e67e22', padding: '8px 15px', borderRadius: '10px', cursor: 'pointer', fontWeight: 'bold', fontSize: '0.85rem' };
const btnNuevaSucursal = { background: '#1e293b', color: 'white', padding: '16px', borderRadius: '16px', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px', fontWeight: 'bold', marginTop: '20px', fontSize: '1rem' };

export default Dashboard;
